/bin/bash -lc "python3 - <<'PY'
import re,json,urllib.request,collections
from pathlib import Path
p=Path('fixtures/api-java/target/dependency-tree.txt')
coords=[]
for line in p.read_text().splitlines():
    m=re.search(r'([A-Za-z0-9_.-]+(?:\\.[A-Za-z0-9_.-]+)*):([A-Za-z0-9_.-]+):(?:[A-Za-z0-9_.-]+:)?(?:jar|war|pom|bundle):(?:[A-Za-z0-9_.-]+:)?(["'^: ]+):(?:compile|runtime|test|provided|system|import)'"', line)
    if m:
        coords.append(m.groups())
seen=set(); uniq=[]
for c in coords:
    if c not in seen:
        seen.add(c); uniq.append(c)
queries=[{'package': {'ecosystem':'Maven','name':f'{g}:{a}'}, 'version':v} for g,a,v in uniq]
allids=collections.defaultdict(list)
for i in range(0,len(queries),100):
    data=json.dumps({'queries':queries[i:i+100]}).encode()
    req=urllib.request.Request('https://api.osv.dev/v1/querybatch', data=data, headers={'Content-Type':'application/json'})
    res=json.load(urllib.request.urlopen(req, timeout=60))
    for q,item in zip(queries[i:i+100], res.get('results', [])):
        for vuln in item.get('vulns') or []:
            allids[(q['package']['name'],q['version'])].append(vuln['id'])

def details(vid):
    req=urllib.request.Request('https://api.osv.dev/v1/vulns/'+vid)
    return json.load(urllib.request.urlopen(req, timeout=60))
for (name,ver),ids in allids.items():
    fixed=set(); events=[]
    summaries=[]
    for vid in ids:
        d=details(vid)
        summaries.append((vid,d.get('summary','')))
        for aff in d.get('affected',[]):
            pkg=aff.get('package',{})
            if pkg.get('ecosystem')=='Maven' and pkg.get('name')==name:
                for r in aff.get('ranges',[]):
                    for ev in r.get('events',[]):
                        if 'fixed' in ev:
                            fixed.add(ev['fixed']); events.append((vid,ev['fixed']))
    print(f'## {name}@{ver}')
    print('vulns:', ', '.join(ids))
    print('fixed:', ', '.join(sorted(fixed)) or 'NONE')
    for vid, s in summaries[:3]: print(' ',vid, s[:140].replace('\\n',' '))
PY"

