/bin/bash -lc "mvn -B dependency:tree -Dscope=test -DoutputType=text -DoutputFile=target/dependency-tree-after.txt >/tmp/deptree.log && python3 - <<'PY'
import re,json,urllib.request,collections
from pathlib import Path
p=Path('target/dependency-tree-after.txt')
coords=[]
for line in p.read_text().splitlines():
    m=re.search(r'([A-Za-z0-9_.-]+(?:\\.[A-Za-z0-9_.-]+)*):([A-Za-z0-9_.-]+):(?:[A-Za-z0-9_.-]+:)?(?:jar|war|pom|bundle):(?:[A-Za-z0-9_.-]+:)?(["'^: ]+):(?:compile|runtime|test|provided|system|import)'"', line)
    if m: coords.append(m.groups())
seen=set(); uniq=[]
for c in coords:
    if c not in seen: seen.add(c); uniq.append(c)
queries=[{'package': {'ecosystem':'Maven','name':f'{g}:{a}'}, 'version':v} for g,a,v in uniq]
allv=[]
for i in range(0,len(queries),100):
    req=urllib.request.Request('https://api.osv.dev/v1/querybatch',data=json.dumps({'queries':queries[i:i+100]}).encode(),headers={'Content-Type':'application/json'})
    res=json.load(urllib.request.urlopen(req, timeout=60))
    for q,item in zip(queries[i:i+100],res.get('results',[])):
        vulns=item.get('vulns') or []
        if vulns: allv.append((q['package']['name'],q['version'],[v['id'] for v in vulns]))
print('deps',len(uniq))
for name,ver,ids in allv:
    print(f'{name}@{ver}: {\", \".join(ids)}')
PY"

